from __future__ import annotations

__all__ = (
    "BlockingPortal",
    "BlockingPortalProvider",
    "check_cancelled",
    "run",
    "run_sync",
    "start_blocking_portal",
    "run_blocking_portal",
)

import threading
from concurrent.futures import Future
from dataclasses import dataclass
from typing import Any, Awaitable, Callable, Optional, Tuple, TypeVar

T_Retval = TypeVar("T_Retval")


class NoEventLoopError(RuntimeError):
    """Raised when an event loop token is required but not available."""


@dataclass
class _BackendStub:
    """Minimal backend stub; real backends run work on an event loop thread."""

    def run_async_from_thread(self, func: Callable[..., Awaitable[Any]], args: Tuple[Any, ...], token: Any | None = None):
        raise NotImplementedError("Backend run_async_from_thread is not implemented in this stub")

    def run_sync_from_thread(self, func: Callable[..., Any], args: Tuple[Any, ...], token: Any | None = None):
        raise NotImplementedError("Backend run_sync_from_thread is not implemented in this stub")


@dataclass
class EventLoopToken:
    """Simplified token holding a backend and an optional native token."""
    native_token: Any | None = None
    backend: _BackendStub = _BackendStub()


class _ThreadLocals:
    """Simple thread-local holder for a current EventLoopToken."""

    def __init__(self) -> None:
        self._local = threading.local()

    @property
    def current_token(self) -> EventLoopToken:
        try:
            return self._local.token  # type: ignore[attr-defined]
        except AttributeError as exc:
            raise AttributeError("no current token set for this thread") from exc

    @current_token.setter
    def current_token(self, value: EventLoopToken) -> None:
        self._local.token = value


threadlocals = _ThreadLocals()


def _token_or_error(token: Optional[EventLoopToken]) -> EventLoopToken:
    """Return the provided token or the thread-local token, or raise if neither exists."""
    if token is not None:
        return token
    try:
        return threadlocals.current_token
    except AttributeError:
        raise NoEventLoopError(
            "Not running inside an AnyIO worker thread, and no event loop token was provided"
        ) from None


def run(func: Callable[..., Awaitable[T_Retval]], *args: object, token: Optional[EventLoopToken] = None) -> T_Retval:
    """Run an async callable from a worker thread via the backend associated with token."""
    explicit = token is not None
    token = _token_or_error(token)
    return token.backend.run_async_from_thread(func, args, token.native_token if explicit else None)


def run_sync(func: Callable[..., T_Retval], *args: object, token: Optional[EventLoopToken] = None) -> T_Retval:
    """Run a synchronous callable in the event loop thread via the backend associated with token."""
    explicit = token is not None
    token = _token_or_error(token)
    return token.backend.run_sync_from_thread(func, args, token.native_token if explicit else None)


class BlockingPortal:
    """A simple context manager exposing run/run_sync helpers bound to a token."""

    def __init__(self, token: EventLoopToken) -> None:
        self._token = token
        self._closed = False

    def run(self, func: Callable[..., Awaitable[T_Retval]], *args: object) -> T_Retval:
        if self._closed:
            raise RuntimeError("BlockingPortal is closed")
        return run(func, *args, token=self._token)

    def run_sync(self, func: Callable[..., T_Retval], *args: object) -> T_Retval:
        if self._closed:
            raise RuntimeError("BlockingPortal is closed")
        return run_sync(func, *args, token=self._token)

    def close(self) -> None:
        self._closed = True

    def __enter__(self) -> "BlockingPortal":
        return self

    def __exit__(self, exc_type, exc, tb) -> None:  # pragma: no cover - trivial
        self.close()


@dataclass
class BlockingPortalProvider:
    """Callable provider that returns a BlockingPortal bound to a token."""
    token: EventLoopToken

    def __call__(self) -> BlockingPortal:
        return BlockingPortal(self.token)


def start_blocking_portal(token: Optional[EventLoopToken] = None) -> BlockingPortal:
    """Create and return a BlockingPortal bound to the given or current token."""
    token = _token_or_error(token)
    return BlockingPortal(token)


def run_blocking_portal(func: Callable[[BlockingPortal], T_Retval], *args: object, token: Optional[EventLoopToken] = None) -> T_Retval:
    """Convenience helper: start a portal, call func(portal, *args), then close the portal."""
    portal = start_blocking_portal(token)
    try:
        return func(portal, *args)
    finally:
        portal.close()


def check_cancelled(fut: Future) -> None:
    """Raise RuntimeError if the given Future has been cancelled."""
    if fut.cancelled():
        raise RuntimeError("Operation cancelled")